output.rtl/cache_mshr.sv:
`define NOTCONNECTED_PIN(x) /* ... */

module cache_mshr #(
    parameter INSTANCE_ID                   = "mo_mshr"             ,
    parameter MSHR_SIZE                     = 32                    ,
    parameter CS_LINE_ADDR_WIDTH            = 10                    ,
    parameter WORD_SEL_WIDTH                = 4                     ,
    parameter WORD_SIZE                     = 4                     ,
    parameter MSHR_ADDR_WIDTH               = $clog2(MSHR_SIZE)     ,
    parameter TAG_WIDTH                     = 32 - (CS_LINE_ADDR_WIDTH+ $clog2(WORD_SIZE) + WORD_SEL_WIDTH),
    parameter CS_WORD_WIDTH                 = WORD_SIZE * 8 ,
    parameter DATA_WIDTH                    = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH
    );

(* SystemVerilog syntax for parameters *)

reg clk;
reg reset;

input wire allocate_valid,
        allocate_addr[CS_LINE_ADDR_WIDTH-1:0],
        allocate_data[DATA_WIDTH-1:0],
        allocate_rw,
        allocate_id[MSHR_ADDR_WIDTH-1:0],
        allocate_pending,
        allocate_previd[MSHR_ADDR_WIDTH-1:0],
        finalize_valid,
        finalize_id[MSHR_ADDR_WIDTH-1:0];

output wire allocate_ready,
        allocate_pending,
        allocate_previd[MSHR_ADDR_WIDTH-1:0];

output reg [MSHR_ADDR_WIDTH-1:0] allocate_id;
output reg [MSHR_ADDR_WIDTH-1:0] allocate_prev_id;
output reg [MSHR_ADDR_WIDTH-1:0] allocate_ready;

output reg [DATA_WIDTH-1:0] entry_data;
reg [MSHR_ADDR_WIDTH-1:0] cache_line_addr;

// Internal signals
reg [DATA_WIDTH-1:0] entry_data_in;
reg [MSHR_ADDR_WIDTH-1:0] index;
reg [1:0] next_ptr;
reg [1:0] prev_ptr;

always @(*) begin
    index = 0;
    for (int i = 0; i < MSHR_SIZE; i = i + 1) begin
        next_ptr = i + 1;
        prev_ptr = i;
        index = i;
    end
end

always @(posedge clk or posedge reset) begin
    if (reset) begin
        clk <= 0;
        next_ptr <= 0;
        prev_ptr <= 0;
        index <= 0;
    end else begin
        if (allocate_valid) begin
            if (head == 0) begin
                // Allocate first available slot
                head <= index;
                next_ptr <= 0;
                prev_ptr <= 0;
                index <= 0;
                allocate_ready = 1;
                allocate_pending = 0;
                allocate_previd <= 0;
            end else begin
                // Find the first free entry after head
                index = head;
                while (next_ptr != 0 && index != head) begin
                    index = next_ptr;
                    next_ptr = next_ptr + 1;
                end
                if (index != 0) begin
                    // Insert between head and next_ptr
                    // Need to adjust pointers
                    next_ptr = index;
                    prev_ptr = head;
                    head = index;
                    next_ptr = index + 1;
                    index = 0;
                end else begin
                    // No free slot, overflow?
                end
            end

            // Set entry data
            entry_data = allocate_data;
            // etc.
        end else begin
            allocate_ready = 0;
            allocate_pending = 1;
            allocate_previd <= index;
        end
    end
end

// Provide outputs
assign allocate_id = head;
assign allocate_prev_id = prev_ptr;
assign allocate_ready = 1;
assign allocate_pending = 0;
assign allocate_previd = 0;

endmodule

module cache_mshr #(
    parameter INSTANCE_ID = "mo_mshr",
    parameter MSHR_SIZE = 32,
    parameter CS_LINE_ADDR_WIDTH = 10,
    parameter WORD_SEL_WIDTH = 4,
    parameter WORD_SIZE = 4,
    parameter MSHR_ADDR_WIDTH = $clog2(MSHR_SIZE),
    parameter TAG_WIDTH = 32 - (CS_LINE_ADDR_WIDTH + $clog2(WORD_SIZE) + WORD_SEL_WIDTH),
    parameter CS_WORD_WIDTH = WORD_SIZE * 8,
    parameter DATA_WIDTH = WORD_SEL_WIDTH + WORD_SIZE + CS_WORD_WIDTH + TAG_WIDTH
) (
    input wire clk,
    input wire reset,

    // memory fill
    input wire fill_valid,
    input wire [MSHR_ADDR_WIDTH-1:0] fill_id,
    output wire [CS_LINE_ADDR_WIDTH-1:0] fill_addr,

    // dequeue
    output wire dequeue_valid,
    output wire [CS_LINE_ADDR_WIDTH-1:0] dequeue_addr,
    output wire dequeue_rw,
    output wire [DATA_WIDTH-1:0] dequeue_data,
    output wire [MSHR_ADDR_WIDTH-1:0] dequeue_id,
    input wire dequeue_ready,

    // allocate
    input wire allocate_valid,
    output wire allocate_ready,
    input wire [CS_LINE_ADDR_WIDTH-1:0] allocate_addr,
    input wire allocate_rw,
    input wire [DATA_WIDTH-1:0] allocate_data,
    output wire [MSHR_ADDR_WIDTH-1:0] allocate_id,
    output wire allocate_pending,
    output wire [MSHR_ADDR_WIDTH-1:0] allocate_previd,

    // finalize
    input wire finalize_valid,
    input wire [MSHR_ADDR_WIDTH-1:0] finalize_id
);

    reg [CS_LINE_ADDR_WIDTH-1:0] cs_line_addr_table [0:MSHR_SIZE-1];
    reg [MSHR_SIZE-1:0] entry_valid_table_q, entry_valid_table_d;
    reg [MSHR_SIZE-1:0] is_write_table;

    reg [MSHR_SIZE-2:0] next_ptr_valid_table_q, next_ptr_valid_table_d;
    reg [MSHR_ADDR_WIDTH-1:0] next_index_ptr [0:MSHR_SIZE-1]; // ptr to the next index

    reg allocate_pending_q, allocate_pending_d;

    reg [MSHR_ADDR_WIDTH-1:0] allocate_id_q, allocate_id_d;

    wire [MSHR_ADDR_WIDTH-1:0] prev_idx;
    reg [MSHR_ADDR_WIDTH-1:0] prev_idx_q;

    reg dequeue_valid_q, dequeue_valid_d;
    reg [MSHR_ADDR_WIDTH-1:0] dequeue_id_q, dequeue_id_d;

    wire allocate_fire = allocate_valid && allocate_ready;

    reg [MSHR_SIZE-1:0] addr_matches;
    for (genvar i = 0; i < MSHR_SIZE; ++i) begin : g_addr_matches
        assign addr_matches[i] = entry_valid_table_q[i] && (cs_line_addr_table[i] == allocate_addr) && allocate_fire;
    end

    wire [MSHR_SIZE-1:0] match_with_no_next = addr_matches & ~next_ptr_valid_table_q;
    wire full_d;

    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_idx (
            .data (~entry_valid_table_q),
            .leading_zeros (allocate_id_d),
            .all_zeros (full_d)
    );

    leading_zero_cnt #(
            .DATA_WIDTH (MSHR_SIZE),
            .REVERSE (1)
    ) allocate_prev_idx (
            .data (match_with_no_next),
            .leading_zeros (prev_idx),
            `NOTCONNECTED_PIN(all_zeros) // not connected
    );

    always @(*) begin
        entry_valid_table_d     = entry_valid_table_q;
        next_ptr_valid_table_d  = next_ptr_valid_table_q;

        if (allocate_fire) begin
            entry_valid_table_d[allocate_id_d] = 1;
            next_ptr_valid_table_d[allocate_id_d] = 0;
        end

        if (allocate_pending_d) begin
            next_ptr_valid_table_d[prev_idx] = 1;
        end
    end

    always @(posedge clk) begin
        if (reset) begin
            entry_valid_table_q  <= '0;
            next_ptr_valid_table_q  <=  0;
            allocate_pending_q <= 0 ;
        end else begin
            entry_valid_table_q  <= entry_valid_table_d;
            next_ptr_valid_table_q  <= next_ptr_valid_table_d;
            allocate_pending_q <= allocate_pending_d ; 
        end

        if (allocate_fire) begin
            cs_line_addr_table[allocate_id_d]   <= allocate_addr;
            is_write_table[allocate_id_d]       <= allocate_rw;
        end

        if (allocate_pending_d) begin
            next_index_ptr[prev_idx] <= allocate_id_d;
        end

    end

    always @(posedge clk) begin
        if (reset) begin
            allocate_id_q       <=  0 ;
            prev_idx_q          <= 0 ;
        end else begin
            if (allocate_fire) begin
                allocate_id_q       <=  allocate_id_d       ;
                prev_idx_q          <= prev_idx ;
            end
        end
    end

    // SP RAM
    reg [DATA_WIDTH-1:0] ram [0:MSHR_SIZE-1];
    reg [DATA_WIDTH-1:0] dequeue_data_int;
    always @(posedge clk) begin
        if (allocate_fire) begin
            ram[allocate_id_d] <= allocate_data ;
        end
    end

    assign allocate_pending_d = |addr_matches;
    assign allocate_id = allocate_id_q;
    assign allocate_ready = ~full_d;
    assign allocate_previd = prev_idx_q;

    assign allocate_pending = allocate_pending_q;

    // output fill and dequeue signal updates
    always @(posedge clk) begin
        if (allocate_fire) begin
            dequeue_valid_q   <= 1'b1;
            dequeue_id_q       <= dequeue_addr;
            dequeue_rw_q       <= 1'b0;
            dequeue_data_q     <= 32'h0;
            dequeue_ready_q    <= 1'b0;
        end else if (dequeue_valid_q) begin
            dequeue_valid_d   <= 1'b1;
            dequeue_id_d       <= dequeue_id_q;
            dequeue_rw_d       <= 1'b1;
            dequeue_data_d     <= dequeue_data_q;
            dequeue_ready_d    <= 1'b1;
        end else begin
            dequeue_valid_q   <= 1'b0;
            dequeue_id_q       <= 0;
            dequeue_rw_d       <= 1'b0;
            dequeue_data_d     <= 32'h0;
            dequeue_ready_d    <= 1'b0;
        end
    end

    always @(posedge clk) begin
        if (allocate_fire) begin
            if (dequeue_valid_d) begin
                dequeue_valid_q <= 1'b0;
                dequeue_id_q      <= dequeue_addr;
                dequeue_rw_q      <= 1'b1;
                dequeue_data_d     <= dequeue_data_d;
                dequeue_ready_q    <= 1'b0;
            end
        end
    end

    assign dequeue_valid_d = dequeue_valid_q;
    assign dequeue_id_d = dequeue_id_q;
    assign dequeue_data_d = dequeue_data_q;
    assign dequeue_ready_d = dequeue_ready_q;

    assign dequeue_addr = dequeue_addr_q;

    assign dequeue_rw = dequeue_rw_q;

    assign dequeue_data = dequeue_data_d;

    assign dequeue_id = dequeue_id_q;

    assign dequeue_ready = dequeue_ready_q;

    assign allocate_pending_d = |addr_matches;

    assign allocate_id_q = allocate_id_d;

    assign allocate_ready = ~full_d;

    assign allocate_previd = prev_idx_q;

endmodule

