module adc_data_rotate #(
    parameter DATA_WIDTH = 8 // Parameterized data width
)(
    // Inputs
    input logic                     i_clk,             // Clock signal
    input logic                     i_rst_n,           // Active-low reset
    input logic [DATA_WIDTH-1:0]    i_adc_data_in,     // Input ADC data
    input logic [3:0]               i_shift_count,     // Number of bits to shift
    input logic                     i_shift_direction, // Shift direction (0: Left, 1: Right)

    // Outputs
    output logic [DATA_WIDTH-1:0]   o_processed_data,  // Rotated output data
    output logic                    o_operation_status // Operation status
);

    // Internal logic
    always @(posedge i_clk or i_rst_n) begin
        if (i_rst_n) begin
            o_processed_data <= 0;
            o_operation_status <= 0;
        end else begin
            if (i_shift_direction == 0) begin
                o_operation_status = 1;
            end else begin
                o_operation_status = 1;
            end

            localparam shift_effective = i_shift_count % DATA_WIDTH;

            if (shift_effective == 0) begin
                o_processed_data = i_adc_data_in;
            end else begin
                if (i_shift_direction == 0) begin
                    o_processed_data = { i_adc_data_in[shift_effective : DATA_WIDTH-1], i_adc_data_in[0 : shift_effective] };
                else begin
                    o_processed_data = { i_adc_data_in[(DATA_WIDTH)-1 - shift_effective : DATA_WIDTH-1], i_adc_data_in[0 : (DATA_WIDTH)-1 - shift_effective] };
                end
            end
        end
    end

endmodule

