module bit_sync #(
    parameter STAGES = 2
) (
    input  logic aclk,    
    input  logic bclk,    
    input  logic rst_n,   
    input  logic adata,   
    output logic aq2_data,
    output logic bq2_data 
);

    logic [STAGES-1:0] a_sync_chain, b_sync_chain;

    // Synchronization for bclk domain
    always_ff @(posedge bclk or negedge rst_n) begin
        if (!rst_n)
            b_sync_chain <= {STAGES{1'b0}};
        else
            b_sync_chain <= {b_sync_chain[STAGES-2:0], adata};
    end

    assign bq2_data = b_sync_chain[STAGES-1];

    // Synchronization for aclk domain
    always_ff @(posedge aclk or negedge rst_n) begin
        if (!rst_n)
            a_sync_chain <= {STAGES{1'b0}};
        else
            a_sync_chain <= {a_sync_chain[STAGES-2:0], adata};
    end

    assign aq2_data = a_sync_chain[STAGES-1];

endmodule

output.rtl/cvdp_copilot_bus_arbiter.sv:
module bus_arbiter (
    input wire reset,
    input wire clk,
    input wire req1,
    input wire req2,
    output reg grant1,
    output reg grant2
);

    localparam IDLE    = 3'b000,
                   GRANT_1 = 3'b001,
                   GRANT_2 = 3'b010,
                   CLEAR   = 3'b011;

    reg [2:0] state;
    reg [2:0] next_state;

    always @(posedge clk or posedge reset) begin
        if (reset)
            state <= IDLE;
        else
            state <= next_state;
    end

    always @(*) begin
        next_state = state;

        case (state)
            IDLE: begin
                next_state = GRANT_1;
            end

            GRANT_1: begin
                next_state = GRANT_2;
                grant1 = 1'b0;
                grant2 = 1'b1;
            end

            GRANT_2: begin
                next_state = CLEAR;
                grant1 = 1'b0;
                grant2 = 1'b0;
            end

            CLEAR: begin
                next_state = IDLE;
                grant1 = 1'b0;
                grant2 = 1'b0;
            end

        endcase
    endelse

    always @(next_state) begin
        case (next_state)
            GRANT_1: begin
                if (~req1) grant1 = 1'b1;
                else grant1 = 1'b0;
                grant2 = 1'b0;
            end

            GRANT_2: begin
                if (~req2) grant1 = 1'b1;
                else grant1 = 1'b0;
                grant2 = 1'b0;
            end

            CLEAR: begin
                grant1 = 1'b0;
                grant2 = 1'b0;
            end

            default: grant1 = 1'b0; grant2 = 1'b0;
        endcase
    end

    always @(posedge clk or posedge reset) begin
        if (reset)
            grant1 <= 1'b0;
            grant2 <= 1'b0;
        end
    end

endmodule

input.rtl/cvdp_copilot_bus_arbiter.sv:
module cvdp_copilot_bus_arbiter (
    input reset,
    input clk,
    input req1,
    input req2,
    output reg grant1,
    output reg grant2
    );

// State Encoding
localparam IDLE        = 3'b000,
            GRANT_1     = 3'b001,
            GRANT_2     = 3'b010,
            MASTER1_PRI = 3'b011,
            CLEAR       = 3'b100;

// STATE REGISTERS
reg [2:0] state;      // Current state
reg [2:0] next_state; // Next state

// State Transition
always @(posedge clk or posedge reset)
begin
    if (reset)
        state <= IDLE;
    else
        state <= next_state;
end

// Next State Logic
always @(*) begin
    next_state = state; // Default assignment
    case (state)
        IDLE: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
        end
        GRANT_2: begin
            if (!req2 && !req1)
                next_state = IDLE; // Both requests deasserted
            else if (!req2 && req1)
                next_state = GRANT_1; // Switch to GRANT_1 if req1 is still asserted
        end
        GRANT_1: begin
            if (!req1 && !req2)
                next_state = IDLE; // Both requests deasserted
            else if (req2)
                next_state = GRANT_2; // req2 has priority
        end
        MASTER1_PRI: begin
            if (req2)
                next_state = GRANT_2; // Grant Master 2 if req2 is asserted
            else if (req1)
                next_state = GRANT_1; // Grant Master 1 if only req1 is asserted
            else
                next_state = IDLE; // No requests, transition to IDLE
        end
        CLEAR: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
            else
                next_state = IDLE; // Default to IDLE if no requests
        end
        default: next_state = IDLE;
    endcase
end

// Output Logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        grant1 <= 1'b0;
        grant2 <= 1'b0;
    end else begin
        case (next_state)
            IDLE: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
            GRANT_1: begin
                grant1 <= 1'b1;
                grant2 <= 1'b0;
            end
            GRANT_2: begin
                grant1 <= 1'b0;
                grant2 <= 1'b1;
            end
            MASTER1_PRI: begin
                grant1 <= 1'b0; // During this state, neither master is granted
                grant2 <= 1'b0;
            end
            CLEAR: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
        endcase
    end
end

endmodule

