    assign o_vector_2 = {bus[27:28], bus[23:20], bus[15:12], bus[7:4], bus[1:0]};
    assign o_vector_3 = {bus[27:28], bus[23:20], bus[15:12], bus[7:4], bus[1:0]};
    assign o_vector_4 = {bus[27:28], bus[23:20], bus[15:12], bus[7:4], bus[1:0]};

