module continuous_adder (
    input logic         clk,         // Clock signal
    input logic         reset,       // Reset signal, Active high and Synchronous
    input logic [7:0]   data_in,     // Input data stream (8-bit)
    input logic         data_valid,  // Input data valid signal
    output logic [7:0]  sum_out,     // Output the accumulated sum
    output logic        sum_ready    // Signal to indicate sum is output and accumulator is reset
);

    logic [7:0] sum_accum;          // Internal accumulator to store the running sum

    // Sequential logic for sum accumulation
    always_ff @(posedge clk) begin
        if (reset) begin
            // On reset, clear the accumulator, reset sum_out and sum_ready
            sum_accum         <= 8'd0;
            sum_ready         <= 1'b0;
        end
        else begin
            if (data_valid) begin
                // Add input data to the accumulator
                sum_accum     <= sum_accum + data_in;

                // Check if the accumulated sum is >= 100
                if (sum_accum + data_in >= 8'd100) begin
                    // Output the current sum and reset the accumulator
                    sum_out   <= sum_accum + data_in; // Output the accumulated sum
                    sum_ready <= 1'b1;                // Indicate that the sum is ready
                    sum_accum <= 8'd0;                // Reset the accumulator
                end
                else begin
                    // Continue accumulating, but no output until the sum reaches 100
                    sum_ready <= 1'b0;                // No output yet
                end
            end
        end
    end

endmodule

output.rtl/cont_adder_top.sv:
module continuous_adder (
    input logic         clk,
    input logic         reset,
    input logic [7:0]   data_in,
    input logic         data_valid,
    output logic [7:0]  sum_out,
    output logic        sum_ready
);

    localparam integer DATA_WIDTH = 8;
    localparam integer THRESHOLD_VALUE = 100;
    localparam boolean SIGNED_INPUTS = 1;

    logic [7:0] sum_accum;
    logic sum_ready;

    always_ff @(posedge clk) begin
        if (reset) begin
            sum_accum <= 8'd0;
            sum_ready <= 1'b0;
        end else begin
            if (data_valid) begin
                if (SIGNED_INPUTS) begin
                    sum_accum <= sum_accum + data_in;

                    if (sum_accum >= THRESHOLD_VALUE) or (sum_accum <= -THRESHOLD_VALUE) begin
                        sum_out <= sum_accum + data_in;
                        sum_ready <= 1'b1;
                    end else begin
                        sum_ready <= 1'b0;
                    end
                end
                else begin
                    if (sum_accum + data_in >= 8'd100) begin
                        sum_out <= sum_accum + data_in;
                        sum_ready <= 1'b1;
                    end else begin
                        sum_ready <= 1'b0;
                    end
                end
            end
        end
    end

endmodule

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;
use IEEE.NUMERIC_STD.ALL;

entity continuous_adder is
    generic (
        DATA_WIDTH  : integer := 32;
        WINDOW_SIZE : integer := 16;
        THRESHOLD_VALUE_1 : integer := 50;
        THRESHOLD_VALUE_2 : integer := 100
    );
    port (
        clk              : in  STD_LOGIC;
        reset            : in  STD_LOGIC;
        data_in          : in  signed [DATA_WIDTH-1:0];
        data_valid       : in  STD_LOGIC;
        window_size      : in  WINDOW_SIZE;
        sum_out          : out signed [DATA_WIDTH-1:0];
        avg_out          : out signed [DATA_WIDTH-1:0];
        sum_ready        : out STD_LOGIC;
        threshold_1      : out std_logic;
        threshold_2      : out std_logic;
        threshold_comb   : out std_logic_vector(THRESHOLD_VALUE_1 downto THRESHOLD_VALUE_2);
        sum_comb         : out std_logic_vector(DATA_WIDTH downto 0);
    );
end entity continuous_adder;

