module cont_adder #(
    parameter DATA_WIDTH = 32,
    parameter THRESHOLD_VALUE_1 = 50,
    parameter THRESHOLD_VALUE_2 = 100,
    parameter THRESHOLD_VALUE_3 = 150,
    parameter ACCUM_MODE  = 0,
    parameter WEIGHT     = 1,
    parameter SAT_MAX    = (2**(DATA_WIDTH-1))-1,
    parameter SAT_MIN    = -(2**(DATA_WIDTH-1))
) (
    input  logic                         clk,
    input  logic                         reset,
    input  logic                         accum_clear,
    input  logic                         enable,
    input  logic signed [DATA_WIDTH-1:0] data_in,
    input  logic                         data_valid,
    input  logic [15:0]                  window_size,
    output logic signed [DATA_WIDTH-1:0] sum_out,
    output logic signed [DATA_WIDTH-1:0] avg_out,
    output logic                         threshold_1,
    output logic                         threshold_2,
    output logic                         threshold_3,
    output logic                         sum_ready,
    output logic                         busy
);

  typedef enum logic [1:0] {IDLE, ACCUM, DONE} state_t;
  state_t state;
  logic signed [DATA_WIDTH-1:0] sum_accum;
  logic [15:0] sample_count;
  logic signed [DATA_WIDTH-1:0] weighted_in_reg;
  logic signed [DATA_WIDTH-1:0] new_sum;
  logic signed [DATA_WIDTH-1:0] sat_sum;

  // Initialise state and counters
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      state <= IDLE;
      sum_accum <= 0;
      sample_count <= 0;
    end else begin
      if (enable && data_valid) begin
        case (state)
          IDLE: begin
            state <= ACCUM;
            sum_accum <= 0;
            sample_count <= 0;
          end
          ACCUM: begin
            sum_accum <= weighted_in_reg;
            sample_count <= sample_count + 1;
            if ((sample_count + 1) >= window_size) state <= DONE;
          end
          DONE: begin
            state <= IDLE;
            sum_accum <= 0;
            sample_count <= 0;
          end
          default: state <= IDLE;
        endcase
      end else
        state <= IDLE;
    end
  end

  // Summation logic
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      sum_out <= 0;
      avg_out <= 0;
      sum_ready <= 0;
      threshold_1 <= 0;
      threshold_2 <= 0;
      threshold_3 <= 0;
      busy <= 0;
    end else begin
      busy <= (state == ACCUM);
      if (state == DONE) begin
        sum_out <= sum_accum;
        avg_out <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
        sum_ready <= 1;
        if ((sum_accum >= SAT_MAX) || (sum_accum <= -SAT_MAX))
          threshold_1 <= 1;
        else
          threshold_1 <= 0;
        if ((sum_accum >= SAT_MIN) || (sum_accum <= -SAT_MIN))
          threshold_2 <= 1;
        else
          threshold_2 <= 0;
        if ((sum_accum >= THRESHOLD_VALUE_1) || (sum_accum <= -THRESHOLD_VALUE_1))
          threshold_3 <= 1;
        else
          threshold_3 <= 0;
      end else begin
        sum_out <= 0;
        avg_out <= 0;
        sum_ready <= 0;
        threshold_1 <= 0;
        threshold_2 <= 0;
        threshold_3 <= 0;
      end
    end
  end

  // Outputs
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      sum_out <= 0;
      avg_out <= 0;
      sum_ready <= 0;
      threshold_1 <= 0;
      threshold_2 <= 0;
      threshold_3 <= 0;
      busy <= 0;
    end else begin
      if (state == ACCUM) begin
        sum_out <= sum_accum;
        avg_out <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
        sum_ready <= 1;
      end else begin
        sum_out <= 0;
        avg_out <= 0;
        sum_ready <= 0;
      end
    end
  end

endmodule

