  output        s_valid  ,
  output [31:0] s_data 
);

reg [31:0] m0_pending_data;
reg [31:0] m1_pending_data;
reg m0_ready;
reg m1_ready;
reg slave_ready;
reg master_selected;

always @(posedge clk or posedge rst_n) begin
  if (!rst_n) begin
    m0_ready <= 0;
    m1_ready <= 0;
    slave_ready <= 0;
    master_selected <= 0;
    m0_pending_data <= 0;
    m1_pending_data <= 0;
  end else begin
    if (m0_ready) begin
      if (m0_valid && m0_data != 0) begin
        slave_ready <= 1;
        m0_pending_data <= m0_data;
        m0_ready <= 0;
      end
