                    dot_length_reg <= dot_length_in;
                    if (start_in) begin
                        state <= COMPUTE;
                        acc <= 0;
                        cnt <= 0;
                    end
                end
                default: state <= IDLE;
            endcase
        end
    end

    always @(posedge clk_in or negedge reset_in) begin
        if (reset_in) begin
            state <= IDLE;
            dot_product_out <= 0;
            dot_product_valid_out <= 0;
            dot_product_error_out <= 0;
        end else begin
            if (dot_product_valid_out) begin
                dot_product_valid_out <= 1;
                dot_product_error_out <= 0;
            end else begin
                dot_product_error_out <= 1;
            end
        end
    end

endmodule

