        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1; 
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= i_block_fifo_data[DATA_WIDTH-1:0];
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0; 
                            next_state  <= IDLE;
                        end else begin
                            next_state <= READ_FIFO;
                        end
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL (
    input  clk,
    input  reset,
    input  push,
    input  pop,
    input  data_in[DATA_WIDTH-1:0],
    output data_out,
    output full,
    output empty
);

    localparam FILO_DEPTH = 16; // default
    localparam DATA_WIDTH   = 8;   // default

    reg [DATA_WIDTH-1:0] data;
    reg top;
    reg full_flag;
    reg empty_flag;

    always @(posedge clk) begin
        if (reset) begin
            top <= 0;
            empty_flag <= 1;
            full_flag <= 0;
        end else begin
            if (push && !full_flag) begin
                top <= top + 1;
                if (top >= FILO_DEPTH) top <= 0;
                data[top] <= data_in;
            end

            if (pop && !empty_flag) begin
                top <= top - 1;
                if (top < 0) top <= FILO_DEPTH - 1;
                data_out <= data[top];
            end

            full_flag <= (top == 0);
            empty_flag <= (top == FILO_DEPTH - 1);

            if (push && pop) begin
                // feedthrough case
                data_out <= data_in;
                full_flag <= 0;
                empty_flag <= 1;
            end
        end
    end

endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

