module FindFasterClock (
    input wire clk_A,
    input wire clk_B,
    input wire rst_n,
    output reg A_faster_than_B,
    output reg valid
);

    reg measure_B;
    reg [31:0] b_count;
    reg [31:0] periodA;
    reg done_A;
    reg measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;
    reg done_B;

    reg [1:0] stateA;
    reg [1:0] stateB;

    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA <= A_IDLE;
            measure_B <= 0;
            b_count <= 0;
            periodA <= 0;
            done_A <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    if (measure_A) begin
                        stateA <= A_COUNT;
                    end else begin
                        stateA <= A_IDLE;
                    end
                end
                A_COUNT: begin
                    if (measure_A) begin
                        b_count <= b_count + 1;
                    end
                    if (b_count == 32) begin // arbitrary, but we can stop after some cycles
                        stateA <= A_DONE;
                        done_A <= 1;
                    end
                end
                A_DONE: begin
                    // nothing
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB <= B_IDLE;
            measure_A <= 0;
            a_count <= 0;
            periodB <= 0;
            done_B <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    if (measure_B) begin
                        stateB <= B_COUNT;
                    end else begin
                        stateB <= B_IDLE;
                    end
                end
                B_COUNT: begin
                    if (measure_B) begin
                        a_count <= a_count + 1;
                    end
                    if (a_count == 32) begin
                        stateB <= B_DONE;
                        done_B <= 1;
                    end
                end
                B_DONE: begin
                    // nothing
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // Output logic
    assign A_faster_than_B = (periodB > periodA) ? 1 : 0;
    assign valid = done_A && done_B;

endmodule

output.rtl/SR_flipflop.sv:
module SR_flipflop(
    input i_S,
    input i_R,
    input i_clk,
    input i_rst_b,
    output reg o_Q,
    output reg o_Q_b
);

    // Always block triggered on the positive edge of the clock
    always @(posedge i_clk or negedge i_rst_b)
    begin
        if (!i_rst_b) {
            o_Q <= 1'b0;
            o_Q_b <= 1'b1;
        }
        else {
            if (i_S && i_R) begin
                o_Q <= 1'b0;
                o_Q_b <= 1'b1;
            }
            else {
                o_Q <= i_S;
                o_Q_b <= ~o_Q;
            }
        }
    end

endmodule

output.rtl/JK_flipflop.sv:
module JK_flipflop(
    input i_J,       // J input of the JK flip-flop
    input i_K,       // K input of the JK flip-flop
    input i_clk,     // Clock input
    input i_rst_b,   // Asynchronous reset, active low
    output reg o_Q,  // Q output
    output reg o_Q_b // Inverted Q output
);

    // Always block triggered on the rising edge of the clock or the falling edge of the reset
    always @(posedge i_clk or negedge i_rst_b)  //Edge triggering will allow to stop race condition and toggle Q when J,K =1,1.
    begin
        if (!i_rst_b) // If reset is active (low)
        begin
            o_Q <= 1'b0;   // Set Q to 0
            o_Q_b <= 1'b1; // Set Q_b to 1 (inverted Q)
        end
        else
        begin
            if (i_J == 1'b0 && i_K == 1'b0)
            begin
                o_Q <= o_Q;
            end
            else if (i_J == 1'b0 && i_K == 1'b1)
            begin
                o_Q <= 0;
                o_Q_b <= 1;
            end
            else if (i_J == 1'b1 && i_K == 1'b0)
            begin
                o_Q <= 1;
                o_Q_b <= 0;
            end
            else if (i_J == 1'b1 && i_K == 1'b1)
            begin
                o_Q <= ~o_Q_b;
                o_Q_b <= ~o_Q;
            end
        end
    end

endmodule

output.rtl/fsm_seq_detector.sv:
module fsm_seq_detector (
    input wire clk_in,
    input wire rst_in,
    input wire seq_in,
    output reg seq_detected
);

    // State encoding (3‑bit state machine: S0 … S7)
    enum class x { S0, S1, S2, S3, S4, S5, S6, S7 };
    localparam state_t cur_state = x::S0;

    // Sequence pattern (8‑bit) in binary
    localparam seq_pattern = 8'b10110001;

    // Always block driven by the clock
    always @(posedge clk_in or negedge rst_in) begin
        if (!rst_in) begin
            cur_state <= x::S0;
            seq_detected <= 0;
        end else begin
            case (cur_state)
                3'b000: // S0 – expecting first bit ‘1’
                    case (seq_in == 1'b1) : cur_state <= 3'b001;
                    default                     : cur_state <= 3'b100;
                // Continue with the remaining 7 states – omitted for brevity
                3'b001: case (seq_in == 1'b0) : cur_state <= 3'b010;
                3'b010: case (seq_in == 1'b1) : cur_state <= 3'b011;
                3'b011: case (seq_in == 1'b1) : cur_state <= 3'b100;
                3'b100: case (seq_in == 1'b0) : cur_state <= 3'b000;
                3'b101: case (seq_in == 1'b1) : cur_state <= 3'b110;
                3'b110: case (seq_in == 1'b0) : cur_state <= 3'b000;
                3'b111: case (seq_in == 1'b1) : cur_state <= 3'b000;
                default: cur_state <= 3'b111;
            endcase
        endcase
    end

    // Detect the complete sequence only after the 8th bit
    assign seq_detected = seq_pattern[7] && cur_state == x::S7;

endmodule

