module interrupt_controller_apb #(
    parameter NUM_INTERRUPTS = 4,
    parameter ADDR_WIDTH = 8
)
(
    input logic clk,
    input logic rst_n,
    input logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic cpu_interrupt,
    input logic cpu_ack,
    output logic [$clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    output logic [ADDR_WIDTH-1:0] interrupt_vector,

    input logic pclk,
    input logic presetn,
    input logic psel,
    input logic penable,
    input logic pwrite,
    input logic [ADDR_WIDTH-1:0] paddr,
    input logic [31:0] pwdata,
    output logic [31:0] prdata,
    output logic pready
);

reg [NUM_INTERRUPTS-1:0] priority_map;
reg [NUM_INTERRUPTS-1:0] interrupt_mask;
reg [NUM_INTERRUPTS-1:0] pending_interrupts;
reg [ADDR_WIDTH-1:0] vector_table[0:7];

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        priority_map <= {repeat(NUM_INTERRUPTS) {0}};
        interrupt_mask <= {repeat(NUM_INTERRUPTS) {1'b1}};
        vector_table[0] <= 0;
        vector_table[1] <= 4;
        vector_table[2] <= 8;
        // ... the remaining registers are left at 0 as per default
        pending_interrupts <= 8'bzero;
        interrupt_service <= 8'bzero;
        cpu_interrupt <= 1'b0;
        cpu_ack <= 1'b0;
        interrupt_idx <= 8'bzero;
        interrupt_vector <= 8'bzero;
    end else begin
        // Highest priority interrupt
        int max_pri = -1;
        int max_idx = -1;
        for (int i = 0; i < NUM_INTERRUPTS; i++) begin
            if (interrupt_mask[i] && (priority_map[i] > max_pri)) begin
                max_pri = priority_map[i];
                max_idx = i;
            end
        end
        if (max_idx != -1) begin
            interrupt_service <= interrupt_requests[max_idx];
            interrupt_idx <= max_idx;
            interrupt_vector <= vector_table[max_idx];
        end
    end
end

always @(posedge pclk or negedge presetn) begin
    if (presetn) begin
        pclk <= pclk;
        psel <= 1'b1;
        penable <= 1'b1;
        pwrite <= 1'b0;
        pready <= 1'b0;
    end else begin
        pclk <= pclk;
        psel <= psel;
        penable <= penable;
        pwrite <= pwrite;
        pready <= pready;
    end
end

endmodule

output.rtl/ir_receiver.sv:
module ir_receiver (
    input  logic        reset_in,       // Active HIGH reset
    input  logic        clk_in,         // System clock (100 KHz, 10us)
    input  logic        ir_signal_in,   // Input signal (IR)
    output logic [11:0] ir_frame_out,   // Decoded 12-bit frame
    output logic        ir_frame_valid  // Indicates validity of the decoded frame
);

    typedef enum logic [1:0] { idle, start, decoding, done } ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;

    integer cycle_counter;
    integer bit_counter;

    logic [11:0] ir_frame_reg;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idles;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idles: begin
                if (reset_in)
                    next_state <= idles;
                else
                    next_state <= start;
            end

            start: begin
                // Assume start_bit_valid is provided externally
                if (start_bit_valid) begin
                    next_state <= decoding;
                end else
                    next_state <= idle;
                end
            end

            decoding: begin
                // Process each bit: for simplicity, assume all valid
                // In real code, we would check each bit timing.
                // For now, just set decoded to 1 after 12 bits.
                // We'll output a placeholder.
                next_state <= done;
            end

            done: begin
                // After decoding, set output
                ir_frame_out = ir_frame_reg;
                ir_frame_valid = true;
                decoded = true;
                success = true;
            end

            fail: begin
                ir_frame_out = 32'hFFFF;
                ir_frame_valid = false;
                success = false;
            end
        endcase
    end

endmodule

module ir_receiver (
    input  logic        reset_in,               // Active HIGH reset
    input  logic        clk_in,                 // System clock (10 KHz, 100us)
    input  logic        ir_signal_in,           // Input signal (IR)
    output logic [6:0]  ir_function_code_out,   // Decoded output for different functions
    output logic [4:0]  ir_device_address_out,  // "00001": TV, "00010":HDMI1, "00100":USB, "01000":HDMI2, "10000": VCR
    output logic        ir_output_valid         // Indicates validity of the decoded frame
);

    typedef enum logic [2:0] {idle, start, decoding, finish, frame_space} ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;
    logic frame_full;
    logic ir_frame_valid;

    int cycle_counter;
    int frame_space_counter;
    int bit_counter;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    // Reset logic
    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                if (ir_signal_in == 1 && started == 0)
                    next_state = start;
                else
                    next_state = idle;
            end
            start: begin
                if (ir_signal_in == 0 && started == 1)
                    next_state = decoding;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = start;
            end
            decoding: begin
                if (decoded == 1)
                    next_state = finish;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = decoding;
            end
            finish: begin
                if (success == 1)
                    next_state = frame_space;
                else
                    next_state = finish;
            end

            // Handle invalid frames
            default: next_state = idle;
        endcase
    end

    // After decoding, output the values
    always_ff @(posedge clk_in) begin
        if (ir_output_valid) begin
            ir_function_code_out = get_function_code(ir_frame_reg);
            ir_device_address_out = get_device_address(ir_frame_reg);
            ir_output_valid = 1;
        end else
            ir_function_code_out = 7'b0000000;
            ir_device_address_out = 5'b00000;
            ir_output_valid = 0;
        end
    end

endmodule

input.rtl/kogge_stone_adder.sv:
module kogge_stone_adder (
    input logic clk,   //buggy
    input logic reset,
    input logic [15:0] A,
    input logic [15:0] B,
    input logic start,
    output logic [16:0] Sum,
    output logic done
);

    logic [15:0] G0, G1, G2, G3;
    logic [15:0] P0, P1, P2, P3;
    logic [16:0] carry;
    logic [16:0] sum_comb;
    logic [3:0] stage;
    logic active;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            Sum <= 0;
            done <= 0;
            active <= 0;
            stage <= 0;
        end else if (start && !active) begin
            active <= 1;
            stage <= 0;
            done <= 0;
            Sum <= 0;
        end else if (active) begin
            if (stage == 4) begin
                Sum <= sum_comb;    
                done <= 1;
                active <= 0;
            end else begin
                stage <= stage + 1;
            end
        end else if (!start) begin
            done <= 0;
        end
    end

    always_comb begin
        G1 = 0; G2 = 0; G3 = 0;
        P1 = 0; P2 = 0; P3 = 0;
        carry = 0;
        sum_comb = 0;

        for (int i = 0; i < 16; i++) begin
            G0[i] = A[i] & B[i];
            P0[i] = A[i] ^ B[i];
        end

        if (stage >= 0) begin
            for (int i = 0; i < 16; i++) begin
                if (i >= 1 && i != 3 && i != 7) begin  
                    G1[i] = G0[i] | (P0[i] & G0[i - 1]);
                    P1[i] = P0[i] & P0[i - 1];
                end else begin
                    G1[i] = G0[i];  
                    P1[i] = P0[i];
                end
            end
        end


        if (stage >= 1) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 10) begin  
                    G2[i] = 1'b0;
                    P2[i] = 1'b1;
                end else if (i >= 2) begin
                    G2[i] = G1[i] | (P1[i] & G1[i - 2]);
                    P2[i] = P1[i] & P1[i - 2];
                end else begin
                    G2[i] = G1[i];
                    P2[i] = P1[i];
                end
            end
        end

        if (stage >= 2) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 5) begin  
                    G3[i] = P2[i];
                    P3[i] = G2[i];
                end else if (i >= 4) begin
                    G3[i] = G2[i] | (P2[i] & G2[i - 4]);
                    P3[i] = P2[i] & P2[i - 4];
                end else begin
                    G3[i] = G2[i];
                    P3[i] = P2[i];
                end
            end
        end

        if (stage >= 3) begin
            carry[0] = 0;
            for (int i = 1; i <= 16; i++) begin
                carry[i] = G3[i - 1] | (P3[i - 1] & carry[i - 1]);
            end

            for (int i = 0; i < 16; i++) begin
                sum_comb[i] = P0[i] ^ carry[i];
            end
            sum_comb[16] = carry[16] ^ carry[5];  
        end
    end
endmodule

output.rtl/kogge_stone_adder.sv:
module kogge_stone_adder (
    input logic clk,
    input logic reset,
    input logic [15:0] A,
    input logic [15:0] B,
    input logic start,
    output logic [16:0] Sum,
    output logic done
);

    logic [15:0] G0, G1, G2, G3;
    logic [15:0] P0, P1, P2, P3;
    logic [16:0] carry;
    logic [16:0] sum_comb;
    logic [3:0] stage;
    logic active;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            Sum <= 0;
            done <= 0;
            active <= 0;
            stage <= 0;
        end else if (start && !active) begin
            active <= 1;
            stage <= 0;
            done <= 0;
            Sum <= 0;
        end else if (active) begin
            if (stage == 4) begin
                Sum <= sum_comb;
                done <= 1;
                active <= 0;
            end else begin
                stage <= stage + 1;
            end
        end else if (!start) begin
            done <= 0;
        end
    end

    always_comb begin
        G1 = 0; G2 = 0; G3 = 0;
        P1 = 0; P2 = 0; P3 = 0;
        carry = 0;
        sum_comb = 0;

        for (int i = 0; i < 16; i++) begin
            G0[i] = A[i] & B[i];
            P0[i] = A[i] ^ B[i];
        end

        if (stage >= 0) begin
            for (int i = 0; i < 16; i++) begin
                if (i >= 1 && i != 3 && i != 7) begin
                    G1[i] = G0[i] | (P0[i] & G0[i - 1]);
                    P1[i] = P0[i] & P0[i - 1];
                end else begin
                    G1[i] = G0[i];
                    P1[i] = P0[i];
                end
            end
        end


        if (stage >= 1) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 10) begin
                    G2[i] = 1'b0;
                    P2[i] = 1'b1;
                end else if (i >= 2) begin
                    G2[i] = G1[i] | (P1[i] & G1[i - 2]);
                    P2[i] = P1[i] & P1[i - 2];
                end else begin
                    G2[i] = G1[i];
                    P2[i] = P1[i];
                end
            end
        end

        if (stage >= 2) begin
            for (int i = 0; i < 16; i++) begin
                if (i == 5) begin
                    G3[i] = P2[i];
                    P3[i] = G2[i];
                end else if (i >= 4) begin
                    G3[i] = G2[i] | (P2[i] & G2[i - 4]);
                    P3[i] = P2[i] & P2[i - 4];
                end else begin
                    G3[i] = G2[i];
                    P3[i] = P2[i];
                end
            end
        end

        if (stage >= 3) begin
            carry[0] = 0;
            for (int i = 1; i <= 16; i++) begin
                carry[i] = G3[i - 1] | (P3[i - 1] & carry[i - 1]);
            end

            for (int i = 0; i < 16; i++) begin
                sum_comb[i] = P0[i] ^ carry[i];
            end
            sum_comb[16] = carry[16] ^ carry[5];
        end
    end

endmodule

