    output logic dec_valid_out,       // Output valid signal
    output logic [N-1:0] dec_data_out // N-bit output decoded data
);

    // Instantiate the Manchester encoder module
    manchester_encoder #(
        .N(N)
    ) encoder_dut (
        .clk_in(clk_in),
