module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

localparam [7:0] START_SYMBOL = 8'hFB;
localparam [7:0] END_SYMBOL   = 8'hFD;
localparam       PKT_BYTES    = 20;

typedef enum logic [1:0] {
    S_IDLE     = 2'b00,
    S_ACTIVE   = 2'b01,
    S_WAIT_END = 2'b10,
    S_ERROR    = 2'b11
} state_t;

state_t curr_state, nxt_state;

logic [7:0]    byte_cnt;
logic [159:0]  pkt_reg;

// State Register
always_ff @(posedge clk or negedge reset) begin
    if (!reset)
        curr_state <= S_IDLE;
    else
        curr_state <= nxt_state;
end

// Next State Logic
always_comb begin
    case (curr_state)
        S_IDLE: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_IDLE;

        S_ACTIVE: 
            if (byte_cnt == PKT_BYTES)
                nxt_state = S_WAIT_END;
            else
                nxt_state = S_ACTIVE;

        S_WAIT_END: 
            if (pkt_reg[159:152] == END_SYMBOL)
                nxt_state = S_IDLE;
            else
                nxt_state = S_ERROR;

        S_ERROR: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_ERROR;

        default: nxt_state = S_IDLE;
    endcase
end

// Insert logic to:
// 1. Update `byte_cnt` and `pkt_reg` during `S_ACTIVE`.
// 2. Validate the packet and update `pkt_data`, `pkt_count`, and flags in `S_WAIT_END`.
// 3. Set `error_detected` appropriately in `S_ERROR`.

endmodule

output.rtl/cvdp_prbs_gen.sv:
module cvdp_prbs_gen #(
    parameter INT CHECK_MODE = 0,
    int POLY_LENGTH = 31,
    int POLY_TAP = 3,
    int WIDTH = 16
) (
    input wire clk,
    input wire rst,
    input wire [WIDTH-1] data_in,
    output reg [WIDTH-1] data_out
);

localparam bool get_expected_bit(int i) = (i == 0 ? 1 : (prbs_reg[POLY_LENGTH-1] ^ prbs_reg[POLY_TAP]));

reg [WIDTH-1] prbs_reg;

initial begin
    if (rst)
        prbs_reg <= {WIDTH{1'b1}};
end

always @(posedge clk) begin
    if (rst)
        prbs_reg <= {WIDTH{1'b1}};
    else
        prbs_reg <= prbs_reg[WIDTH-1:]1b1;
end

always @(posedge clk) begin
    if (DATA_IN_VALID && !rst) begin
        data_in = 0;
    end
end

always @(posedge clk) begin
    if (rst)
        prbs_reg <= {WIDTH{1'b1}};
    else
        prbs_reg <= prbs_reg[WIDTH-1:]1b1;
end

always @(posedge clk) begin
    if (CHECK_MODE) begin
        always @(posedge clk) begin
            if (rst)
                data_out <= {WIDTH{1'b0}};
            else
                data_out <= {WIDTH{1'b0}};
        end
    end
    else begin
        always @(posedge clk) begin
            if (rst)
                prbs_reg <= {WIDTH{1'b1}};
            else
                prbs_reg <= prbs_reg[WIDTH-1:]1b1;
        end
        for (int i = 0; i < WIDTH; i++) begin
            int expected = get_expected_bit(i);
            int actual = prbs_reg[POLY_LENGTH-1] ^ prbs_reg[POLY_TAP];
            data_out[i] = data_in[i] ^ actual;
        end
    end
end

input.rtl/prim_max_find.sv:
module prim_max_find #(
  parameter int NumSrc = 8,
  parameter int Width = 8,
  // Derived parameters
  localparam int SrcWidth = $clog2(NumSrc),
  localparam int NumLevels = $clog2(NumSrc) - 1,
  localparam int NumNodes = 2**(NumLevels+1)
) (
  input                         clk_i,
  input                         rst_ni,
  input [Width*NumSrc-1:0]      values_i,    // Flattened Input values
  input [NumSrc-1:0]            valid_i,     // Input valid bits
  output wire [Width-1:0]       max_value_o, // Maximum value
  output wire [SrcWidth-1:0]    max_idx_o,   // Index of the maximum value
  output wire                   max_valid_o  // Whether any of the inputs is valid
);

  reg [NumNodes-1:0]                vld_tree [0:NumLevels];
  reg [SrcWidth-1:0]                 idx_tree [0:NumLevels][NumNodes-1:0];
  reg [Width-1:0]                    max_tree [0:NumLevels][NumNodes-1:0];

  generate
    for (genvar level = 0; level <= NumLevels; level++) begin : gen_tree
      localparam int Base0 = (2**level);
      localparam int Base1 = (2**(level+1));

      for (genvar offset = 0; offset < 2**level; offset++) begin : gen_level
        localparam int Pa = Base0 + offset;
        localparam int C0 = Base1 + 2*offset;
        localparam int C1 = Base1 + 2*offset + 1;

        if (level == NumLevels) begin : gen_leafs
          if (offset < NumSrc) begin : gen_assign
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end else begin
                vld_tree[level][Pa] <= valid_i[offset];
                idx_tree[level][Pa] <= offset;
                max_tree[level][Pa] <= values_i[(offset+1)*Width : offset*Width];
              end
            end
          end else begin : gen_tie_off
            always @(posedge clk_i or negedge rst_ni) begin
              if (!rst_ni) begin
                vld_tree[level][Pa] <= 1'b0;
                idx_tree[level][Pa] <= '0;
                max_tree[level][Pa] <= '0;
              end
            end
          end
        end

        else begin : gen_nodes
          reg sel; 
          always @(posedge clk_i or negedge rst_ni) begin
            if (!rst_ni) begin
              vld_tree[level][Pa] <= 1'b0;
              idx_tree[level][Pa] <= '0;
              max_tree[level][Pa] <= '0;
            end else begin
              sel = (~vld_tree[level+1][C0] & vld_tree[level+1][C1]) |
                    (vld_tree[level+1][C0] & vld_tree[level+1][C1] & (max_tree[level+1][C1] > max_tree[level+1][C0]));

              vld_tree[level][Pa] <= (sel) ? vld_tree[level+1][C1] : vld_tree[level+1][C0];
              idx_tree[level][Pa] <= (sel) ? idx_tree[level+1][C1] : idx_tree[level+1][C0];
              max_tree[level][Pa] <= (sel) ? max_tree[level+1][C1] : max_tree[level+1][C0];
            end
          end
        end
      end : gen_level
    end : gen_tree
  endgenerate

  assign max_valid_o = vld_tree[0][0];
  assign max_idx_o   = idx_tree[0][0];
  assign max_value_o = max_tree[0][0];

endmodule

