output.rtl/sdram_controller.sv:
module sdram_controller (
    input wire clk,
    input wire reset,
    input wire [23:0] addr,
    input wire [15:0] data_in,
    input wire read, write,
    input wire sdram_clk,
    input wire sdram_cke,
    input wire sdram_cs,
    input wire sdram_ras,
    input wire sdram_cas,
    input wire sdram_we,
    input wire sdram_addr,
    input wire sdram_ba,
    input wire sdram_dq,
    output reg data_out,
    output reg sdram_clk,
    output reg sdram_cke,
    output reg sdram_cs,
    output reg sdram_ras,
    output reg sdram_cas,
    output reg sdram_we,
    output reg sdram_addr,
    output reg sdram_ba,
    output reg sdram_dq
);

reg [3:0] state;

always @(posedge clk) begin
    case (state)
        INIT: begin
            // initialization phase, 10 clock cycles
            state <= IDLE;
        end
        IDLE: begin
            // check for read or write requests
            if (!read && !write) state <= ACTIVATE;
            if (read) state <= READ;
            if (write) state <= WRITE;
        end
        ACTIVATE: begin
            // activate the row
            state <= READ;
        end
        READ: begin
            // simulate read operation
            data_out <= sdram_dq;
            state <= IDLE;
        end
        WRITE: begin
            // simulate write operation
            data_in <= data_out;
            state <= IDLE;
        end
        REFRESH: begin
            // simulate refresh
            state <= IDLE;
        end
    endcase
end

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,
    input i_rst_b,
    input [3:0] i_operand_a,
    input [3:0] i_operand_b,
    input [2:0] i_opcode,
    input [7:0] i_key_in,
    output reg [7:0] o_result
);

parameter logic [7:0] p_key = 8'hAA;

always @(posedge i_clk or negedge i_rst_b) begin
    if (!i_rst_b) begin
        o_result <= 8'b0;
    end else begin
        if (i_key_in == p_key) begin
            case (i_opcode)
                4'b000: o_result = i_operand_a + i_operand_b;
                4'b001: o_result = i_operand_a - i_operand_b;
                4'b010: o_result = i_operand_a * i_operand_b;
                4'b011: o_result = i_operand_a & i_operand_b;
                4'b100: o_result = ~i_operand_a;
                4'b101: o_result = ~i_operand_a ^ i_operand_b;
                4'b110: o_result = i_operand_a ^ i_operand_b;
                4'b111: o_result = ~(i_operand_a ^ i_operand_b);
            endcase
        end else
            o_result <= 8'b0;
        // No else needed for this block
    end
end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface(
    input p_addr_width bit i_addr,
    input p_data_width bit i_data_in,
    input i_key_in,
    input i_read_write_enable,
    input i_capture_pulse,
    input i_reset_bar
);

reg [31:0] internal_key;
reg [31:0] data_out;
bit o_error;

always @(posedge i_capture_pulse) begin
    if (i_reset_bar) begin
        internal_key <= 32'h0;
        data_out <= 32'h0;
        o_error <= 1'b1;
        o_data_out <= 0;
    end else begin
        if (i_read_write_enable == 1) begin
            if (i_key_in == internal_key) begin
                data_out <= i_data_in;
                o_error <= 1'b0;
            end else begin
                o_error <= 1'b1;
                data_out <= 0;
            end
        end else begin
            o_error <= 1'b1;
            data_out <= 0;
        end
    end
end

assign o_data_out = (i_read_write_enable == 1 && i_key_in == internal_key) ? i_data_in : 32'h0;

always @(*) begin
    assign internal_key = p_configurable_key;
    assign data_out = o_data_out;
    assign o_error = o_error;
end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising‑edge triggered)
    input wire i_rst_n,         // Active‑low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4‑bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    reg [3:0] delay;            // Holds the 4‑bit delay value
    reg count_phase;            // Accumulated cycles for the counting phase
    reg counting;               // Flag indicating that we are counting
    reg done;                   // Flag that signals the end of the counting phase

    always @(i_clk) begin
        if (i_rst_n) begin
            // Reset all state variables on reset
            o_time_left <= 8'd1000;
            o_processing <= 0;
            o_completed <= 0;
            delay <= 4'd0;
            count_phase <= 0;
            counting <= 0;
            done <= 0;
        end else begin
            if (i_data_in == 4'b1101) begin
                // Detect the start pattern and shift the next 4 bits into delay
                delay <= i_data_in[4:1];
                next_state = CONFIGURE;
            end else if (counting) begin
                count_phase = (delay[3:0] + 1) * 1000;
                if (o_time_left >= count_phase) begin
                    o_completed <= 1;
                    o_processing <= 0;
                end else begin
                    o_time_left <= o_time_left - 1;
                end
            end else if (done) begin
                // Wait for the acknowledgment signal
                if (i_ack) begin
                    o_completed <= 1;
                    o_processing <= 0;
                    o_time_left <= 8'd1000;
                    count_phase <= 0;
                    delay <= 4'd0;
                    next_state = IDLE;
                end else begin
                    next_state = COUNTING;
                end
            end
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
`timescale 1ns / 1ps

module binary_to_one_hot_decoder_sequential (
    input wire       i_binary_in,
    input wire       i_clk,
    input wire       i_rstb,
    output reg [OUTPUT_WIDTH-1:0] o_one_hot_out
);

    parameter BINARY_WIDTH = 5;
    parameter OUTPUT_WIDTH = 32;

    reg [OUTPUT_WIDTH-1:0] next_state;
    reg         clk_n;

    initial begin
        o_one_hot_out = 0;
    end

    always @(posedge i_clk or negedge i_rstb) begin
        if (!i_rstb) begin
            o_one_hot_out <= 0;
        end else begin
            if (i_clk) begin
                next_state <= 0;
                for (integer j = 0; j < OUTPUT_WIDTH; j++) begin
                    if (i_binary_in[j] == 1'b1) begin
                        next_state[j] = 1'b1;
                    end else begin
                        next_state[j] = 1'b0;
                    end
                end
            end else begin
                next_state <= 0;
            end
            o_one_hot_out <= next_state;
        end
    end

endmodule

