    if (async_reset) begin
        cnt <= 0;
    end else begin
        if (i_rst_n) begin
            cnt <= 0;
        end else begin
            if (i_bit_in) begin
                if (cnt == MAX_COUNT-1) begin
                    cnt <= 0;
