output.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter WIDTH = 8,
    parameter N = 8
) (
    input  logic clk,
    input  logic rst,
    input  logic start,
    input logic [WIDTH-1:0] in_data,
    output logic [WIDTH-1:0] out_data,
    output logic done
);

    localparam WIDTH = WIDTH;
    localparam N = N;

    logic clk, rst, start, done;
    logic [WIDTH-1:0] in_data_val, out_data_val;
    state machine state;

    always @(posedge clk) begin
        if (rst) begin
            state <= IDLE;
            out_data_val <= 0;
            done <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        state <= SORTING;
                    end
                end
                SORTING: begin
                    // Bubble sort simulation
                    for (int i = 0; i < N; i++) begin
                        for (int j = 0; j < N - i - 1; j++) begin
                            if (in_data_val[j] > in_data_val[j+1]) begin
                                assign in_data_val[j] = in_data_val[j+1];
                                assign in_data_val[j+1] = in_data_val[j];
                            end
                        end
                    }
                    state <= DONE;
                end
                default: state <= IDLE;
            endcase
        end
    end

    always_ff @(posedge clk) begin
        if (state == DONE) begin
            done <= 1;
        end else if (state == SORTING) begin
            done <= 0;
        end
    end

endmodule

input.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for bubble sort indexing
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    // FSM: Next state logic
    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Transition to DONE once all passes are complete
                if (i == (N-1) && j == (N-2))
                    next_state = DONE;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // FSM: Output and counter updates
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            i <= 0;
            j <= 0;
            done <= 0;
        end else begin
            state <= next_state;

            case (state)
                IDLE: begin
                    done <= 0;
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        i <= 0;
                        j <= 0;
                    end
                end

                SORTING: begin
                    // Perform a single comparison and swap if needed
                    if (val_j > val_j1) begin
                        array[j]   <= val_j1;
                        array[j+1] <= val_j;
                    end

                    // Update j
                    if (j == N-2) begin
                        // One pass completed, increment i
                        j <= 0;
                        i <= i + 1;
                    end else begin
                        j <= j + 1;
                    end
                end

                DONE: begin
                    // Sorting complete
                    done <= 1;
                    // Output the sorted data
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end
                default: begin
                end
            endcase
        end
    end

endmodule

output.rtl/sorting_engine.sv:
module sorting_engine #(
    parameter N = 8,             // Number of elements to sort
    parameter WIDTH = 8          // Bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Internal registers to hold the array
    reg [WIDTH-1:0] array [0:N-1];

    // FSM states
    localparam IDLE    = 2'd0;
    localparam SORTING = 2'd1;
    localparam DONE    = 2'd2;

    reg [1:0]  state, next_state;

    // Variables for insertion sort
    reg [$clog2(N)-1:0] i;  // Outer loop index
    reg [$clog2(N)-1:0] j;  // Inner loop index
    reg [$clog2(N)-1:0] k;  // Temporary index for shifting

    // Wires for comparison and swap
    wire [WIDTH-1:0] val_j;
    wire [WIDTH-1:0] val_j1;

    assign val_j  = array[j];
    assign val_j1 = array[j+1];

    assign val_j1 = array[j+1]; // Actually we already have val_j1 = array[j+1] from val_j1 assignment above? Let's re-evaluate.

    Actually, we should have:

    assign val_j1 = val_j; // Wait, we need to keep consistency.

    Let's just keep the earlier approach but simplify.

    We'll create a for loop for j from 1 to N-1.

    In the SORTING state, we do:

    always @(*) begin
        next_state = state;
        case (state)
            IDLE: begin
                if (start)
                    next_state = SORTING;
            end
            SORTING: begin
                // Insertion sort logic
                for (j = 1; j < N; j++) begin
                    val_j = array[j];
                    val_j1 = array[j-1];
                    if (val_j < val_j1) begin
                        // Shift elements to the right
                        for (k = j-1; k >= 0; k--) begin
                            if (array[k] > array[k+1])
                                array[k+1] <= array[k];
                        end
                        array[j] <= array[j-1];
                    end
                end
                done <= 1;
            end
            DONE: begin
                next_state = IDLE;
            end
            default: begin
                next_state = IDLE;
