                            // Phase 2: Insert the key at array[j+1]
                            array[j+1] <= key;
                            i <= i + 1;
                            insert_phase <= 0; 
                        end

                        default: insert_phase <= 0;
                    endcase
                end

                DONE: begin
                    // Sorting complete, output the result
                    done <= 1;
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                end

                default: begin
                    // Should not get here
                end
            endcase
        end
    end

endmodule

