                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_serial_communication_top.sv:
module sync_serial_communication_top (
    input wire clk,
    input wire reset_n,
    input data_in,
    input sel,
    output reg serial_out,
    output reg done,
    output serial_clk
);

// Transmitter block
module tx_block (
    input wire clk,
    input wire reset_n,
    input data_in,
    input sel,
    output reg serial_out_tx,
    output reg done_tx,
    output serial_clk_tx
);

always @(posedge clk or posedge reset_n) begin
    if (reset_n) begin
        serial_out_tx <= 1'b0;
        done_tx <= 1'b0;
        serial_clk_tx <= 1'b0;
    end else begin
        if (sel == 3'h0) serial_out_tx <= 1'b0;
        else if (sel == 3'h1) serial_out_tx <= data_in[7:0];
        else if (sel == 3'h2) serial_out_tx <= data_in[15:7];
        else if (sel == 3'h3) serial_out_tx <= data_in[31:16];
        else if (sel == 3'h4) serial_out_tx <= data_in[63:32];
        else serial_out_tx <= 1'b0;

        done_tx <= 1'b0;
        serial_clk_tx <= clk;
    end
end

endmodule

// Receiver block
module rx_block (
    input wire clk,
    input wire reset_n,
    input serial_out_tx,
    input data_in,
    input sel,
    output reg data_out,
    output reg done
);

always @(posedge clk or posedge reset_n) begin
    if (reset_n) begin
        data_out <= 64'h0;
        done <= 1'b0;
        serial_out_tx <= 1'b0;
    end else begin
        data_out <= serial_out_tx;
        done <= serial_clk_tx;
    end
end

endmodule

module sync_serial_communication_top (
    input wire clk,
    input wire reset_n,
    input data_in,
    input sel,
    output reg serial_out,
    output reg done,
    output serial_clk
);

tx_block u1 (.clk(clk), .reset_n(reset_n), .data_in(data_in), .sel(sel), .serial_out(serial_out_tx), .done(done_tx), .serial_clk(serial_clk_tx));
rx_block u2 (.clk(clk), .reset_n(reset_n), .serial_out_tx(serial_out_tx), .data_in(data_in), .sel(sel), .data_out(data_out), .done(done), .serial_clk(serial_clk_tx));

assign serial_out = serial_out_tx;
assign done = done_tx;
assign serial_clk = serial_clk_tx;

endmodule

`timescale 1ns / 1ps
module sync_serial_communication_tx_rx(
    input clk,
    input reset_n,
    input [2:0] sel,
    input [63:0] data_in,
    output [63:0] data_out,
    output done
);

// --- TX Block (minimized combinational logic)
module tx_block(
    input clk,
    input reset_n,
    input [63:0] data_in,
    input [2:0] sel,
    output reg serial_out,
    output reg done,
    output serial_clk
);

reg [63:0] data_reg;
reg [6:0] bit_count;
reg [6:0] reg_count;

always @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg <= 64'h0;
        bit_count <= 7'h0;
        reg_count <= 7'h0;
    end else if (done == 1'b1) begin
        // Empty body – no action needed
    end else if (bit_count > 7'h0) begin
        data_reg >>= 1;
        bit_count = bit_count - 1'b1;
    end else if (reg_count > 7'h0 || bit_count > 7'h0) begin
        serial_out = data_reg[0];
    end
end

// --- RX Block (minimized combinational logic)
module rx_block(
    input wire clk,
    input wire reset_n,
    input wire data_in,
    input wire serial_clk,
    input [2:0] sel,
    output reg done,
    output reg [63:0] data_out
);

reg [63:0] data_reg;
reg [7:0] bit_count;
reg [7:0] count;

always @(posedge serial_clk or negedge reset_n) begin
    if (!reset_n) begin
        data_reg <= 64'h0;
        bit_count <= 8'd0;
    end else begin
        if (done == 1'b1) begin
            bit_count <= 8'b0;
            data_reg <= 64'h0;
        end else begin
            bit_count <= bit_count + 1'b1;
            data_reg[bit_count] <= data_in;
        end
    end
end

endmodule

// Instantiate blocks
tx_block uut_tx_block (
    .clk(clk),
    .reset_n(reset_n),
    .data_in(data_in),
    .sel(sel),
    .serial_out(tx_out),
    .done(tx_done),
    .serial_clk(serial_clk_in)
);

rx_block uut_rx_block (
    .clk(clk),
    .serial_clk(serial_clk_in),
    .reset_n(reset_n),
    .sel(sel),
    .data_in(tx_out),
    .data_out(data_out),
    .done(done)
);

endmodule

output.rtl/thermostat.v:
module thermostat (
    input wire i_clk,
    input wire i_rst,
    input wire i_enable,
    input wire i_fault,
    input wire i_clr,
    input [5:0] i_temp_feedback,
    output reg o_heater_full,
    output reg o_heater_medium,
    output reg o_heater_low,
    output reg o_aircon_full,
    output reg o_aircon_medium,
    output reg o_heater_high? Wait, we don't have a high for heating? The heating outputs are full, medium, low. There's no high for heating? The design didn't mention high heating. The states are full, medium, low. So we only have those.

    output reg o_aircon_full,
    output reg o_aircon_medium,
    output reg o_aircon_low,
    output reg o_fan
);

// reset and enable logic
always @(posedge i_clk or negedge i_rst) begin
    if (i_rst) begin
        o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        o_fan <= 0;
        // reset all outputs
    end else if (i_enable == 0) begin
        o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        o_fan <= 0;
    end else if (i_fault == 1) begin
        o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        o_fan <= 0;
    end else if (i_clr == 1) begin
        o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        o_fan <= 0;
        // after clearing, go to ambient
    end
end

always @(posedge i_clk) begin
    if (!i_rst) begin
        // idle state, default to ambient
        o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        o_fan <= 0;
    end else begin
        // evaluate temperature feedback
        // According to spec: Cold conditions priority first, then hot, then ambient.
        if (i_full_cold) begin
            o_heater_full <= 1;
            // others 0
        end else if (i_medium_cold) begin
            o_heater_medium <= 1;
            // others 0
        end else if (i_low_cold) begin
            o_heater_low <= 1;
            // others 0
        end else if (i_full_hot) begin
            o_heater_full <= 1;
            // others 0
        end else if (i_medium_hot) begin
            o_heater_medium <= 1;
            // others 0
        end else if (i_low_hot) begin
            o_heater_low <= 1;
            // others 0
        end else begin // ambient
            o_heater_full <= 0; o_heater_medium <= 0; o_heater_low <= 0;
        end

        // Cooling similar
        if (i_full_hot) begin
            o_aircon_full <= 1;
            o_aircon_medium <= 0; o_aircon_low <= 0;
        end else if (i_medium_hot) begin
            o_aircon_medium <= 1;
            // others 0
        end else if (i_low_hot) begin
            o_aircon_low <= 1;
            // others 0
        end else begin
            o_aircon_full <= 0; o_aircon_medium <= 0; o_aircon_low <= 0;
        end

        // Fan control: if any heater or aircon output active, or fan on, set to 1
        o_fan <= (o_heater_full || o_heater_medium || o_heater_low || o_aircon_full || o_aircon_medium || o_fan_on);
    end
end

endmodule

