output.rtl/vending_machine.sv:
module vending_machine (
    input  clk,
    input  rst,
    input  item_button,
    input  [2:0] item_selected,
    input  [3:0] coin_input,
    input  cancel,
    output reg dispense_item,
    output reg return_change,
    output reg [4:0] item_price,
    output reg [4:0] change_amount,
    output reg [2:0] dispense_item_id,
    output reg error,
    output reg return_money
);

    // State definitions
    localparam ITERATION_IDLE = 0;
    localparam ITERATION_ITEM_SELECTION = 1;
    localparam ITERATION_PAYMENT_VALIDATION = 2;
    localparam ITERATION_DISPENSING_ITEM = 3;
    localparam ITERATION_RETURN_CHANGE = 4;
    localparam ITERATION_RETURN_MONEY = 5;

    reg [2:0] state;
    reg [2:0] next_state;
    reg item_pressed;
    reg item_displayed;
    reg coins_accumulated;
    reg change_required;
    reg dispense_triggered;
    reg error_flag;

    initial begin
        state = ITERATION_IDLE;
        next_state = ITERATION_IDLE;
        item_pressed = 0;
        item_displayed = 0;
        coins_accumulated = 0;
        change_required = 0;
        dispense_triggered = 0;
        error_flag = 0;
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= ITERATION_IDLE;
            next_state <= ITERATION_IDLE;
            item_pressed <= 0;
            item_displayed <= 0;
            coins_accumulated <= 0;
            change_required <= 0;
            dispense_triggered <= 0;
            error_flag <= 0;
        } else begin
            item_pressed <= item_button;
        end
    end

    always @(item_pressed or coin_input) begin
        case (state)
            ITERATION_IDLE: begin
                if (item_pressed) begin
                    state <= ITERATION_ITEM_SELECTION;
                    next_state <= ITERATION_ITEM_SELECTION;
                end
                item_pressed <= 0;
            end
            ITERATION_ITEM_SELECTION: begin
                if (item_selected == 3'b001) begin
                    state <= ITERATION_PAYMENT_VALIDATION;
                    next_state <= ITERATION_PAYMENT_VALIDATION;
                end else if (item_selected == 3'b010) begin
                    state <= ITERATION_PAYMENT_VALIDATION;
                    next_state <= ITERATION_PAYMENT_VALIDATION;
                end else if (item_selected == 3'b011) begin
                    state <= ITERATION_PAYMENT_VALIDATION;
                    next_state <= ITERATION_PAYMENT_VALIDATION;
                end else if (item_selected == 3'b100) begin
                    state <= ITERATION_PAYMENT_VALIDATION;
                    next_state <= ITERATION_PAYMENT_VALIDATION;
                end else if (item_selected < 3'b001 or item_selected > 3'b100) begin
                    state <= ITERATION_ERROR;
                    next_state <= ITERATION_ERROR;
                end else if (coin_input != 4'b0000 && coin_input != 4'b0001 && coin_input != 4'b0010 && coin_input != 4'b0100) begin
                    state <= ITERATION_ERROR;
                    next_state <= ITERATION_ERROR;
                end
            end
            ITERATION_PAYMENT_VALIDATION: begin
                if (item_displayed) begin
                    item_price = item_selected[3];
                    dispense_item_id = 3'b000;
                    next_state <= ITERATION_DISPENSING_ITEM;
                end else if (coin_input == 4'b0000) begin
                    state <= ITERATION_DISPENSING_ITEM;
                    next_state <= ITERATION_DISPENSING_ITEM;
                end else if (coin_input == 4'b0001) begin
                    state <= ITERATION_PAYMENT_VALIDATION;
                    next_state <= ITERATION_PAYMENT_VALIDATION;
                end else begin
                    state <= ITERATION_ERROR;
                    next_state <= ITERATION_ERROR;
                end
            end
            ITERATION_DISPENSING_ITEM: begin
                dispense_triggered = 1;
                if (coin_input == 4'b0000) begin
                    coins_accumulated += 1;
                    if (coins_accumulated >= item_price) begin
                        state <= ITERATION_RETURN_CHANGE;
                        next_state <= ITERATION_RETURN_CHANGE;
                    end
                end else begin
                    state <= ITERATION_RETURN_CHANGE;
                    next_state <= ITERATION_RETURN_CHANGE;
                end
            end
            ITERATION_RETURN_CHANGE: begin
                if (coin_input == 4'b0010) begin
                    change_required = coin_input;
                    coins_accumulated = 0;
                    dispense_item_id = 3'b001;
                    next_state <= ITERATION_RETURN_MONEY;
                end else begin
                    state <= ITERATION_RETURN_MONEY;
                    next_state <= ITERATION_RETURN_MONEY;
                end
            end
            ITERATION_RETURN_MONEY: begin
                if (coin_input == 4'b0000) begin
                    state <= ITERATION_IDLE;
                    next_state <= ITERATION_IDLE;
                end else if (coin_input == 4'b0001) begin
                    state <= ITERATION_IDLE;
                    next_state <= ITERATION_IDLE;
                end else if (coin_input == 4'b0010) begin
                    state <= ITERATION_IDLE;
                    next_state <= ITERATION_IDLE;
                end else begin
                    state <= ITERATION_IDLE;
                    next_state <= ITERATION_IDLE;
                end
            end
        end
    end

endmodule

output.rtl/vga_controller.sv:
module vga_controller (
    input wire clock,
    input wire reset,
    input wire [7:0] color_in,
    output reg hsync,
    output reg vsync,
    output reg [7:0] red,
    output reg [7:0] green,
    output reg [7:0] blue,
    output reg next_x,
    output reg next_y,
    output wire sync,
    output wire [9:0] next_y_plus_one,
    output wire [9:0] next_x_plus_one,
    output wire [9:0] next_y_plus_one,
    output wire blank
);

initial begin
    hsync = 1'b1;
    vsync = 1'b1;
    red = 8'b0;
    green = 8'b0;
    blue = 8'b0;
    next_x = 10'd0;
    next_y = 10'd0;
    next_y_plus_one = 0;
    next_x_plus_one = 0;
    next_y_plus_one = 0;
    next_y_plus_one = 0;
end

always_ff @(posedge clock) begin
    if (reset) begin
        h_counter <= 0;
        v_counter <= 0;
        hsync = 1'b1;
        vsync = 1'b1;
        red = 8'b0;
        green = 8'b0;
        blue = 8'b0;
        next_x = 10'd0;
        next_y = 10'd0;
    end else begin
        case (h_state)
            H_ACTIVE: begin
                if (h_counter < H_ACTIVE) begin
                    h_counter <= h_counter + 1;
                    next_x = next_x + 1;
                    next_y = next_y + 1;
                end else begin
                    h_state = H_FRONT;
                end
            end
            H_FRONT: begin
                end
            H_PULSE: begin
                h_state = H_BACK;
            end
            H_BACK: begin
                h_state = H_ACTIVE;
            end
        endcase
    end

    case (v_state)
        V_ACTIVE: begin
            if (v_counter < V_ACTIVE) begin
                v_counter <= v_counter + 1;
            end else begin
                v_state = V_FRONT;
            end
        end
        V_FRONT: begin
            vsync = 1'b0;
        end
        V_PULSE: begin
        V_BACK: begin
            v_state = V_ACTIVE;
        end
    endcase
end

assign hsync = h_state == H_ACTIVE;
assign vsync = v_state == V_ACTIVE;
assign red = color_in[7:5];
assign green = color_in[4:2];
assign blue = color_in[1:0];

endmodule

module vga_controller (
    input logic clock,
    input logic reset,
    input logic [7:0] color_in,
    output logic [9:0] next_x,
    output logic [9:0] next_y,
    output logic hsync,
    output logic vsync,
    output logic [7:0] red,
    output logic [7:0] green,
    output logic [7:0] blue,
    output logic sync,
    output logic clk,
    output logic blank,
    output logic [7:0] h_state,
    output logic [7:0] v_state
);

    parameter logic [9:0] H_ACTIVE  = 10'd640;
    parameter logic [9:0] H_FRONT   = 10'd16;
    parameter logic [9:0] H_PULSE   = 10'd96;
    parameter logic [9:0] H_BACK    = 10'd48;
    parameter logic [9:0] V_ACTIVE  = 10'd480;
    parameter logic [9:0] V_FRONT   = 10'd10;
    parameter logic [9:0] V_PULSE   = 10'd2;
    parameter logic [9:0] V_BACK    = 10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    reg h_counter;
    reg v_counter;
    reg h_state;
    reg v_state;
    reg sync;
    reg clk;
    reg blank;

    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            sync        <= LOW;
            clk         <= '0;
            blank        <= '0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            red          <= 0;
            green        <= 0;
            blue         <= 0;
            hsync        <= '0;
            vsync        <= '0;
        end else begin

            case (h_state)
                H_ACTIVE_STATE: begin
                    if (h_counter < H_ACTIVE-1) begin
                        h_counter <= h_counter + 1;
                        hsync <= HIGH;
                    end else begin
                        h_counter <= 10'd0;
                    end
                end

                H_FRONT_STATE: begin
                    if (h_counter < H_FRONT-1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_counter <= 10'd0;
                    end
                    hsync <= HIGH;
                end

                H_PULSE_STATE: begin
                    if (h_counter < H_PULSE-1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_counter <= 10'd0;
                    end
                    hsync <= LOW;
                end

                H_BACK_STATE: begin
                    if (h_counter < H_BACK-1) begin
                        h_counter <= h_counter + 1;
                    end else begin
                        h_counter <= 10'd0;
                    end
                    hsync <= HIGH;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    if (v_counter < V_ACTIVE-1) begin
                        v_counter <= v_counter + 1;
                        vsync <= HIGH;
                    end else begin
                        v_counter <= 10'd0;
                    end
                end

                V_FRONT_STATE: begin
                    if (v_counter < V_FRONT-1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_counter <= 10'd0;
                    end
                    vsync <= HIGH;
                end

                V_PULSE_STATE: begin
                    if (v_counter < V_PULSE-1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_counter <= 10'd0;
                    end
                    vsync <= LOW;
                end

                V_BACK_STATE: begin
                    if (v_counter < V_BACK-1) begin
                        v_counter <= v_counter + 1;
                    end else begin
                        v_counter <= 10'd0;
                    end
                    vsync <= HIGH;
                end
            endcase
        end
    end

    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

    assign red   = (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) ? color_in[0] : 0;
    assign green = (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) ? color_in[1] : 0;
    assign blue  = (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) ? color_in[2] : 0;

endmodule

input.rtl/vga_controller.sv:
module vga_controller (
    input logic clock,      // 25 MHz
    input logic reset,      // Active high
    input logic [7:0] color_in, // Pixel color data (RRRGGGBB)
    output logic [9:0] next_x,  // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0] next_y,  // y-coordinate of NEXT pixel that will be drawn
    output logic hsync,     // HSYNC (to VGA connector)
    output logic vsync,     // VSYNC (to VGA connector)
    output logic [7:0] red, // RED (to resistor DAC VGA connector)
    output logic [7:0] green, // GREEN (to resistor DAC to VGA connector)
    output logic [7:0] blue, // BLUE (to resistor DAC to VGA connector)
    output logic sync,      // SYNC to VGA connector
    output logic clk,       // CLK to VGA connector
    output logic blank,     // BLANK to VGA connector
    output logic [7:0] h_state, // States of Horizontal FSM
    output logic [7:0] v_state  // States of Vertical FSM
);

    parameter logic [9:0] H_ACTIVE  =  10'd640;
    parameter logic [9:0] H_FRONT   =  10'd16;
    parameter logic [9:0] H_PULSE   =  10'd96;
    parameter logic [9:0] H_BACK    =  10'd48;
    parameter logic [9:0] V_ACTIVE  =  10'd480;
    parameter logic [9:0] V_FRONT   =  10'd10;
    parameter logic [9:0] V_PULSE   =  10'd2;
    parameter logic [9:0] V_BACK    =  10'd33;
    parameter logic LOW   = 1'b0;
    parameter logic HIGH  = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;


    logic line_done;
    logic [9:0] h_counter;
    logic [9:0] v_counter;


    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            case (h_state)
                H_ACTIVE_STATE: begin
                   h_counter <= (h_counter == (H_ACTIVE - 1)) ? 10'd0 : (h_counter + 10'd1);
                   hsync     <= HIGH;
                   line_done <= LOW;
                   h_state   <= (h_counter == (H_ACTIVE - 1)) ? H_FRONT_STATE : H_ACTIVE_STATE;
                end
                H_FRONT_STATE: begin
                   h_counter <= (h_counter == (H_FRONT - 1)) ? 10'd0 : (h_counter + 10'd1);
                   hsync     <= HIGH;
                   h_state   <= (h_counter == (H_FRONT - 1)) ? H_PULSE_STATE : H_FRONT_STATE;
                end
                H_PULSE_STATE: begin
                  h_counter <= (h_counter == (H_PULSE - 1)) ? 10'd0 : (h_counter + 10'd1);
                  hsync     <= LOW;
                  h_state   <= (h_counter == (H_PULSE - 1)) ? H_BACK_STATE : H_PULSE_STATE;
                end
                H_BACK_STATE: begin
                  h_counter <= (h_counter == (H_BACK - 1)) ? 10'd0 : (h_counter + 10'd1);
                  hsync     <= HIGH;
                  h_state   <= (h_counter == (H_BACK - 1)) ? H_ACTIVE_STATE : H_BACK_STATE;
                  line_done <= (h_counter == (H_BACK - 1)) ? HIGH: LOW;
                end
            endcase

            case (v_state)
                V_ACTIVE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_ACTIVE - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_ACTIVE - 1) ? V_FRONT_STATE : V_ACTIVE_STATE;
                    end
                    vsync  <= HIGH;
                end
                V_FRONT_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_FRONT - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_FRONT - 1) ? V_PULSE_STATE : V_FRONT_STATE;
                    end
                    vsync  <= HIGH;
                end
                V_PULSE_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_PULSE - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_PULSE - 1) ? V_BACK_STATE : V_PULSE_STATE;
                    end
                    vsync  <= LOW;
                end
                V_BACK_STATE: begin
                    if (line_done == HIGH) begin
                        v_counter <= (v_counter == V_BACK - 1) ? 10'd0 : (v_counter + 10'd1);
                        v_state   <= (v_counter == V_BACK - 1) ? V_ACTIVE_STATE : V_BACK_STATE;
                    end
                    vsync  <= HIGH;
                end
            endcase
            if (h_state == H_ACTIVE_STATE && v_state == V_ACTIVE_STATE) begin
                red       <= {color_in[7:5], 5'd0};
                green     <= {color_in[4:2], 5'd0};
                blue      <= {color_in[1:0], 6'd0};
            end
            else begin
                red       <= 8'd0;
                green     <= 8'd0;
                blue      <= 8'd0;
            end
        end
    end


    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

