output.rtl/virtual2physical_tlb.sv:
module virtual2physical_tlb #(
    parameter ADDR_WIDTH = 8,
    PAGE_WIDTH = 8,
    TLB_SIZE = 4,
    PAGE_TABLE_SIZE = 16
) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    output [PAGE_WIDTH-1:0] physical_address,
    output hit, miss
);

    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;
    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );

endmodule

module TLB #(parameter TLB_SIZE = 4, ADDR_WIDTH = 8, PAGE_WIDTH = 8) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    input tlb_write_enable,
    input flush,
    input [PAGE_WIDTH-1:0] page_table_entry,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg hit,
    output reg miss
);

    reg [ADDR_WIDTH-1:0] virtual_tags[TLB_SIZE-1:0];
    reg [PAGE_WIDTH-1:0] physical_pages[TLB_SIZE-1:0];
    reg [TLB_SIZE-1:0] valid_bits;
    reg [$clog2(TLB_SIZE)-1:0] replacement_index;
    integer i;

    always_comb begin
        hit = 0;
        miss = 1;
        physical_address = 0;

        for (i = 0; i < TLB_SIZE; i = i + 1) begin
            virtual_tags[i] = virtual_tags[i];
            physical_pages[i] = physical_pages[i];
            valid_bits[i] = valid_bits[i];
        end

        if (tlb_write_enable && flush) begin
            // flush operation: set all entries to empty?
            virtual_tags[0] <= 8'b0;
            physical_pages[0] <= 8'b0;
            valid_bits[0] <= 1'b0;
        end

        if (tlb_write_enable && hit) begin
            virtual_tags[0] <= virtual_address;
            physical_pages[0] <= physical_address;
            valid_bits[0] <= 1'b1;
        end

        if (tlb_write_enable && miss) begin
            virtual_tags[0] <= virtual_address;
            physical_pages[0] <= 8'b0;
            valid_bits[0] <= 1'b0;
        end

        if (valid_bits[0]) begin
            hit = virtual_tags[0] == virtual_address;
            miss = ~hit;
        end

    end

endmodule

module PageTableHandler #(
    parameter ADDR_WIDTH = 8,
    PAGE_WIDTH = 8,
    PAGE_TABLE_SIZE = 16
) (
    input clk,
    input reset,
    input miss,
    input [ADDR_WIDTH-1:0] virtual_page,
    output reg [PAGE_WIDTH-1:0] page_table_entry,
    output reg ready
);

    reg [PAGE_WIDTH-1:0] page_table_memory [0:PAGE_TABLE_SIZE-1];

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            page_table_memory[0] <= 8'h0;
            page_table_memory[1] <= 8'h1;
            page_table_memory[2] <= 8'h2;
            page_table_memory[3] <= 8'h3;
            page_table_memory[4] <= 8'h4;
            page_table_memory[5] <= 8'h5;
            page_table_memory[6] <= 8'h6;
            page_table_memory[7] <= 8'h7;
            page_table_memory[8] <= 8'h8;
            page_table_memory[9] <= 8'h9;
            page_table_memory[10] <= 8'hA;
            page_table_memory[11] <= 8'hB;
            page_table_memory[12] <= 8'hC;
            page_table_memory[13] <= 8'hD;
            page_table_memory[14] <= 8'he;
            page_table_memory[15] <= 8'hF;
            ready = 0;
        end else if (miss) begin
            ready = 1;
        end else begin
            ready = 0;
        end
    end

endmodule

module ControlUnit (
    input clk,
    input reset,
    input hit,
    input miss,
    input ready,
    output reg tlb_write_enable,
    output reg flush
);

    reg [1:0] state;

    localparam IDLE = 2'b00,
             FETCH = 2'b01,
             UPDATE = 2'b10;

    always @(posedge clk) begin
        case (state)
            IDLE: begin
                if (ready) begin
                    state <= FETCH;
                end else begin
                    state <= IDLE;
                end
            end
            FETCH: begin
                // fetch next virtual address, etc.
                state <= UPDATE;
            end
            UPDATE: begin
                // update TLB, etc.
                state <= IDLE;
            end
        endcase
    end

    // Additional logic for control unit
endmodule

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8 // Default word width
) (
    input  wire                  clk,               // Clock signal for synchronizing operations
    input  wire                  reset,             // Reset signal to initialize the module
    input  wire [DATA_WIDTH-1:0] data_in,           // Input data, width defined by parameter DATA_WIDTH
    input  wire [DATA_WIDTH-1:0] mask,              // Mask signal to enable/disable change detection for each bit
    input  wire [DATA_WIDTH-1:0] match_pattern,     // Pattern to match for generating the pulse
    input  wire                  enable,            // Enable signal to allow module operation
    input  wire                  latch_pattern,     // Signal to latch the match pattern
    output reg                   word_change_pulse, // Output signal indicating a change in any bit of data_in
    output reg                   pattern_match_pulse, // Output signal indicating a match with the pattern
    output reg [DATA_WIDTH-1:0]  latched_pattern    // Latched pattern for comparison
);

    wire [DATA_WIDTH-1:0] change_pulses;

    reg [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;
    reg                  match_detected;

    genvar i;

    // Instantiate Bit_Change_Detector for each bit
    for (i = 0; i < DATA_WIDTH; i++) begin : bcd
        Bit_Change_Detector uut (
            .clk(clk),
            .reset(reset),
            .bit_in(data_in[i]),
            .mask(mask[i]),
            .match_pattern(match_pattern),
            .enable(enable),
            .latch_pattern(latch_pattern),
            .change_pulse(bit_change_pulse_i)
        );
    end

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in <= {DATA_WIDTH{1'b0}};
            masked_change_pulses <= {DATA_WIDTH{1'b0}};
            word_change_pulse <= 1'b0;
            match_detected <= 1'b0;
            pattern_match_pulse <= 1'b0;
            latched_pattern <= {DATA_WIDTH{1'b0}};
        end else if (enable) begin
            always @(posedge clk) begin
                // Mask the data_in and compare with masked_change_pulses
                masked_data_in = {DATA_WIDTH{1'b0}} ? data_in : {DATA_WIDTH{1'b0}};
                for (int j = 0; j < DATA_WIDTH; j++) begin
                    if (masked_data_in[j] != masked_change_pulses[j]) begin
                        word_change_pulse = 1'b1;
                    end else begin
                        word_change_pulse = 1'b0;
                    end
                }
            end
        end else begin
            word_change_pulse = 1'b0;
        end
    end

    always @(*) begin
        pattern_match_pulse <= (latched_pattern == {DATA_WIDTH{1'b0}} ? match_pattern : 1'b0);
    end

    assign latched_pattern = {DATA_WIDTH{1'b0}} ? data_in : {DATA_WIDTH{1'b0}};

endmodule

output.rtl/Data_Reduction.sv:
module Data_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter DATA_WIDTH         = 4,      // Width of each data element
    parameter DATA_COUNT         = 4,      // Number of data elements
    localparam TOTAL_INPUT_WIDTH = DATA_WIDTH * DATA_COUNT
)
(
    input  wire [TOTAL_INPUT_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0]        reduced_data_out
);

    generate
        genvar bit_index;

        // Iterate over each bit position within a single data word
        for (bit_index = 0; bit_index < DATA_WIDTH; bit_index = bit_index + 1) begin : bit_processing
            wire [DATA_COUNT-1:0] extracted_bits;

            // Extract the bit at position bit_index from each data_in.
            for (digit_index = 0; digit_index < DATA_COUNT; digit_index = digit_index + 1)
                extracted_bits[digit_index] = data_in[digit_index][bit_index];

            // Use Bitwise_Reduction to compute the output bit for this position
            assign reduced_data_out[bit_index] = bitwise_reducer(extracted_bits, REDUCTION_OP, DATA_COUNT);
        end
    endgenerate

endmodule


module Bitwise_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter BIT_COUNT          = 4       // Number of bits to reduce
)
(
    input  wire [BIT_COUNT-1:0] input_bits,
    output reg                  reduced_bit
);

    // Reduction Operation Codes
    localparam [2:0] AND_OP  = 3'b000;
    localparam [2:0] OR_OP   = 3'b001;
    localparam [2:0] XOR_OP  = 3'b010;
    localparam [2:0] NAND_OP = 3'b011;
    localparam [2:0] NOR_OP  = 3'b100;
    localparam [2:0] XNOR_OP = 3'b101;

    int i;
    reg temp_result; // Intermediate result

    always @(*) begin
        // Initialize result with the first bit
        temp_result = input_bits[0];

        // Reduce bits using the selected operation
        for (i = 1; i < BIT_COUNT; i = i + 1) begin
            case (REDUCTION_OP)
                AND_OP, NAND_OP  : temp_result = temp_result & input_bits[i];
                OR_OP,  NOR_OP   : temp_result = temp_result | input_bits[i];
                XOR_OP, XNOR_OP  : temp_result = temp_result ^ input_bits[i];
                default          : temp_result = temp_result & input_bits[i];
            endcase
        end

        // Store the result in the output
        assign reduced_bit = temp_result;
    end

endmodule

